#include <bits/stdc++.h>
using namespace std;
struct Node{
    int data,id;
}cnt[10];
int b[10][10],p[10][10],w[10][10],ans=-1,sum;
bool h[10][10],l[10][10],g[10][10],flag=false;
bool cmp(Node x,Node y){
    return x.data>y.data;
}
void set_thing(int i,int j){
    if(i==1 || j==1 || i==9 || j==9)
        p[i][j]=6;
    else if(i==2 || j==2 || i==8 || j==8)
        p[i][j]=7;
    else if(i==3 || j==3 || i==7 || j==7)
        p[i][j]=8;
    else if(i==4 || j==4 || i==6 || j==6)
        p[i][j]=9;
    else
        p[i][j]=10;
    if(i<=3 && j<=3)
        w[i][j]=1;
    else if(i<=3 && j>3 && j<7)
        w[i][j]=2;
    else if(i<=3 && j>6)
        w[i][j]=3;
    else if(i>3 && i<=6 && j<=3)
        w[i][j]=4;
    else if(i>3 && i<=6 && j>3 && j<7)
        w[i][j]=5;
    else if(i>3 && i<=6 && j>6)
        w[i][j]=6;
    else if(i>6 && j<=3)
        w[i][j]=7;
    else if(i>6 && j>3 && j<7)
        w[i][j]=8;
    else
        w[i][j]=9;
    if(b[i][j]){
    	if(h[i][b[i][j]] || l[j][b[i][j]] || g[w[i][j]][b[i][j]])
    		flag=true;
    	h[i][b[i][j]]=l[j][b[i][j]]=g[w[i][j]][b[i][j]]=true;
    }	
}
void dfs(int x,int y){
	if(x>9){
		ans=max(ans,sum);
		return;
	}
    if(b[cnt[x].id][y]){
    	sum+=b[cnt[x].id][y]*p[cnt[x].id][y];
		if(y==9)
			dfs(x+1,1);
		else
			dfs(x,y+1);
		sum-=b[cnt[x].id][y]*p[cnt[x].id][y];
		return;
	}
    for(int i=1;i<=9;i++)
    	if(!h[cnt[x].id][i] && !l[y][i] && !g[w[cnt[x].id][y]][i]){
    		sum+=i*p[cnt[x].id][y];
    		h[cnt[x].id][i]=l[y][i]=g[w[cnt[x].id][y]][i]=true;
    		if(y==9)
				dfs(x+1,1);
			else
				dfs(x,y+1);
			sum-=i*p[cnt[x].id][y];
    		h[cnt[x].id][i]=l[y][i]=g[w[cnt[x].id][y]][i]=false;
		}
}
int main(){
    for(int i=1;i<=9;i++)
        for(int j=1;j<=9;j++){
        	scanf("%d",&b[i][j]);
        	cnt[i].data+=(b[i][j]>0);
        	cnt[i].id=i;
        	set_thing(i,j);
		}
    /*for(int i=1;i<=9;i++){
    	for(int j=1;j<=9;j++)
    		printf("%d ",b[i][j]);
    	printf("\n");
	}*/
	sort(cnt+1,cnt+10,cmp);
	if(flag)
		printf("-1");
	else{
    	dfs(1,1);
	    printf("%d",ans);
	}
    return 0;
}
